import React from "react";
import { Link } from "react-router-dom";

// 💡 topBanners, bottomBanners 를 받아옵니다.
const Hero = ({ topBanners, bottomBanners }) => {
  return (
    // 전체 컨테이너에 최대 너비(1400px)와 가운데 정렬(margin: 0 auto) 부여
    <section style={{ maxWidth: "97%", margin: "0 auto", padding: "32px 0" }}>
      {/* 상단 5열 그리드 영역 */}
      {/* gap: '16px' 로 이미지 사이 간격 생성 */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(5, 1fr)",
          gap: "16px",
          marginBottom: "40px",
          marginTop: "-25px",
        }}
      >
        {/* 💡 topBanners 로 맵핑 */}
        {topBanners &&
          topBanners.map((item) => (
            <Link
              to={`/detail/${item.id}`} // 💡 여기를 "/detail"로 수정했습니다!
              key={`top-${item.id}`}
              style={{ textDecoration: "none", display: "block" }}
            >
              {/* borderRadius: '8px' 로 모서리 둥글게 */}
              <div
                style={{
                  borderRadius: "8px",
                  overflow: "hidden",
                  aspectRatio: "4/5",
                  marginBottom: "12px",
                }}
              >
                <img
                  src={process.env.PUBLIC_URL +item.imgUrl}
                  alt={item.text}
                  style={{ width: "100%", height: "100%", objectFit: "cover" }}
                />
              </div>
              <div
                style={{
                  textAlign: "center",
                  fontSize: "13px",
                  color: "#999",
                  fontWeight: "500",
                }}
              >
                {item.text}
              </div>
            </Link>
          ))}
      </div>

      {/* 하단 6열 그리드 영역 */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(6, 1fr)",
          gap: "16px",
        }}
      >
        {/* 💡 bottomBanners 로 맵핑 */}
        {bottomBanners &&
          bottomBanners.map((item) => (
            <Link
              to={`/detail/${item.id}`} // 💡 여기도 "/detail"로 수정했습니다!
              key={`bot-${item.id}`}
              style={{ textDecoration: "none", display: "block" }}
            >
              <div
                style={{
                  borderRadius: "6px",
                  overflow: "hidden",
                  aspectRatio: "4/3",
                  marginBottom: "10px",
                  width: "300px",
                  height: "183px",
                }}
              >
                <img
                  src={process.env.PUBLIC_URL +item.imgUrl}
                  alt={item.brand}
                  style={{
                    width: "300px",
                    height: "185px",
                    objectFit: "cover",
                  }}
                />
              </div>
              <div style={{ textAlign: "center" }}>
                <div
                  style={{
                    fontSize: "12.5px",
                    color: "#999",
                    marginBottom: "4px",
                    fontWeight: "500",
                  }}
                >
                  {item.brand}
                </div>
                <div
                  style={{
                    fontSize: "14px",
                    color: "#000",
                    fontWeight: "500",
                    whiteSpace: "pre-line",
                    lineHeight: "1.4",
                  }}
                >
                  {item.desc}
                </div>
              </div>
            </Link>
          ))}
      </div>
    </section>
  );
};

export default Hero;
