import React from "react";
import { Link } from "react-router-dom";

const FooterLifestyle = () => {
  const categoryLinks = [
    { name: "신상품", list: ["전체"] },
    {
      name: "홈 인테리어",
      list: [
        "전체",
        "침구",
        "가구&조명",
        "테이블웨어",
        "프래그런스",
        "소품",
        "욕실",
      ],
    },
    {
      name: "음악&도서",
      list: ["전체", "LP", "CD&카세트", "매거진", "아트북", "포스터", "스티커"],
    },
    {
      name: "테크",
      list: ["전체", "폰케이스", "오디오&헤드폰", "오디오기어", "스테이셔너리"],
    },
    { name: "아웃도어", list: ["전체", "장비", "캐리어", "액세서리"] },
    {
      name: "랭킹",
      list: ["전체", "홈인테리어", "테크", "음악&도서", "아웃도어"],
    },
  ];

  const images = [
    {
      label: "테크",
      src:"/images/footer/footer-09.jpg",
    },
    {
      label: "음악&도서",
      src:"/images/footer/footer-10.jpg",
    },
    {
      label: "도서",
      src:"/images/footer/footer-11.jpg",
    },
    {
      label: "프래그런스",
      src:"/images/footer/footer-12.jpg",
    },
  ];

  return (
    <div
      style={{
        maxWidth: "96%",
        margin: "0 auto",
        padding: "40px 0",
        borderBottom: "1px solid #eaeaea",
        display: "flex",
        justifyContent: "space-between",
        marginTop: "-7px",
      }}
    >
      <div style={{ flex: 1, paddingRight: "40px" }}>
        <div style={{ marginBottom: "33px" }}>
          <span
            style={{
              fontSize: "14px",
              fontWeight: "800",
              color: "#000",
              marginRight: "6px",
            }}
          >
            라이프스타일
          </span>
          <span style={{ fontSize: "14px", color: "#777" }}>전체 1,533개</span>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: "9px" }}>
          {categoryLinks.map((cat, idx) => (
            <div key={idx} style={{ display: "flex" }}>
              <div
                style={{
                  width: "80px",
                  flexShrink: 0,
                  fontSize: "13.8px",
                  color: "#777",
                  fontWeight: "450",
                  marginRight: "15.7px",
                }}
              >
                {cat.name}
              </div>
              <div style={{ display: "flex", gap: "10.5px", flexWrap: "wrap" }}>
                {cat.list.map((item, i) => (
                  <Link
                    to="#"
                    key={i}
                    style={{
                      fontSize: "13.5px",
                      color: i === 0 ? "#000" : "#000",
                      fontWeight: i === 0 ? "525" : "525",
                      textDecoration: "none",
                    }}
                  >
                    {item}
                  </Link>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
      <div style={{ display: "flex", gap: "15px" }}>
        {images.map((img, idx) => (
          <Link
            key={idx}
            to="#"
            style={{
              position: "relative",
              width: "163px",
              aspectRatio: "3/4",
              backgroundColor: "#e8e8e8",
              borderRadius: "3px",
              overflow: "hidden",
            }}
          >
            <img
              src={process.env.PUBLIC_URL + img.src}
              alt={img.label}
              style={{ width: "100%", height: "100%", objectFit: "contain"  }}
            />
            <div
              style={{
                position: "absolute",
                top: 0,
                left: 0,
                width: "100%",
                height: "100%",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                color: "#fff",
                fontSize: "12px",
                fontWeight: "bold",
                textShadow: "0 0 4px rgba(0,0,0,0.5)",
              }}
            >
              {img.label}
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
};

export default FooterLifestyle;
