import React from "react";
import { Link } from "react-router-dom";

const CurationProductCard = ({ item }) => {
  return (
    <Link to={`/product/${item.id}`} style={{ textDecoration: "none", color: "inherit", display: "block" }}>
      <div style={{ width: "100%", textAlign: "center", marginBottom: "60px" }}>
        
        {/* 1. 화면 정중앙에 오는 큼직한 이미지 박스 (이전 설정 그대로 유지!) */}
        <div style={{ 
          width: "100%", 
          maxWidth: "1000px", 
          margin: "0 auto",  
          aspectRatio: "1/1", 
          backgroundColor: "#f4f4f4", 
          overflow: "hidden",
          marginBottom: "15px"
        }}>
          <img 
            src={process.env.PUBLIC_URL +item.imgUrl} 
            alt={item.name} 
            style={{ 
              width: "100%", 
              height: "100%", 
              objectFit: "cover" 
            }} 
          />
        </div>

        {/* 💡 2. 핵심 수정 부분: 브랜드, 가격 싹 빼고 name 하나만 깔끔하게 출력! */}
        <p style={{ 
          fontSize: "13px", 
          color: "#666", 
          lineHeight: "1.5", 
          margin: "0 auto", 
          paddingBottom: "20px",
          fontWeight: "400", 
          maxWidth: "450px", // 텍스트도 이미지 너비에 딱 맞춤
          wordBreak: "keep-all", // 단어 단위로 줄바꿈 되도록 설정
          textDecoration: "underline", // 사진을 보니 텍스트에 밑줄이 있는 것 같아 추가했습니다. (필요 없으면 이 줄은 지우세요!)
          textUnderlineOffset: "3px" // 밑줄 간격 살짝 띄우기
        }}>
          {item.name}
        </p>
        
      </div>
    </Link>
  );
};

export default CurationProductCard;