import React from "react";
import { Link } from "react-router-dom";

const Spotlight = ({ items }) => {
  return (
    <section style={{ width: "100%", marginTop: "60px", marginBottom: "60px" }}>
      {/* 타이틀 영역 */}
      <div style={{ maxWidth: "97%", margin: "0 auto 20px auto" }}>
        <h2
          style={{
            fontSize: "25px",
            fontWeight: "900",
            margin: 0,
            color: "#000",
            marginBottom: "28px",
          }}
        >
          스포트라이트
        </h2>
      </div>

      {/* 전체 가로선 및 회색 배경 영역 */}
      <div
        style={{
          width: "100%",
          backgroundColor: "#f6f6f6",
          borderTop: "1px solid #eaeaea",
          borderBottom: "1px solid #eaeaea",
        }}
      >
        <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)" }}>
          {items &&
            items.map((item, index) => (
              <Link
                to="#"
                key={item.id}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  textDecoration: "none",
                  borderRight: index !== 5 ? "1px solid #eaeaea" : "none",
                }}
              >
                {/* 💡 수정 1. 이미지 영역: 원본과 똑같은 정사각형 비율로 변경 */}
                <div
                  style={{
                    width: "100%",
                    aspectRatio: "1/1", // "3/4" 였던 부분을 "1/1"로 바꿉니다! (정사각형)
                    backgroundColor: "#fff", // 이미지가 로딩되기 전 배경색 (선택사항)
                  }}
                >
                  <img
                    src={process.env.PUBLIC_URL + item.imgUrl} // 💡 로컬 이미지 경로 오류 방지용 PUBLIC_URL 추가
                    alt={item.name || item.desc}
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover", // 빈틈없이 이미지를 꽉 채웁니다
                    }}
                  />
                </div>

                {/* 💡 텍스트 영역: 글자 여백 조절 */}
                <div
                  style={{
                    padding: "22px 16px 25px 16px",
                    textAlign: "center",
                  }}
                >
                  <div
                    style={{
                      fontSize: "12px", // 원본의 작은 글씨 크기에 맞춰 조정 (기존 15px -> 12px)
                      color: "#999",
                      fontWeight: "400",
                      marginBottom: "6px", // 브랜드명과 상품명 사이 여백 조금 더 주기
                      textTransform: "uppercase",
                    }}
                  >
                    {item.brand}
                  </div>
                  <div
                    style={{
                      fontSize: "15px", // 원본 글씨 크기 조정 (기존 17px -> 15px)
                      color: "#111",
                      wordBreak: "keep-all",
                      lineHeight: "1.4",
                    }}
                  >
                    {item.name || item.desc}
                  </div>
                </div>
              </Link>
            ))}
        </div>
      </div>
    </section>
  );
};

export default Spotlight;
