import React from "react";

const EventTemplate = ({ eventInfo }) => {
  return (
    <div style={{ width: "100%", maxWidth: "1850px", margin: "0 auto", paddingBottom: "100px" }}>
      
      {/* 1. 상단 기간 및 타이머 (텍스트 유지) */}
      <div style={{ display: "flex", justifyContent: "space-between", padding: "16px 0", fontSize: "20px", fontWeight: "1000" }}>
        <span>{eventInfo.period}</span>
        <span>남은 시간 {eventInfo.timer}</span>
      </div>

      {/* 2. 대형 배너 이미지 (첫 번째 빨간 동그라미 구역) */}
      {/* 💡 사진 데이터가 있을 때만 회색 배경 박스를 그립니다. (없으면 아예 흔적도 없이 사라짐) */}
      {eventInfo.heroImg && (
        <div style={{ width: "100%", backgroundColor: "#f5f5f5", minHeight: "300px" }}>
          <img src={process.env.PUBLIC_URL +eventInfo.heroImg} alt="spring season banner" style={{ width: "100%", display: "block", objectFit: "cover" }} />
        </div>
      )}

      {/* 3. 캠페인 제목 및 설명 (텍스트 유지) */}
      <div style={{ textAlign: "center", marginTop: "60px", marginBottom: "250px" }}>
        {/* 💡 제목 데이터가 null이면 이 태그 자체가 렌더링되지 않아 빈 여백이 생기지 않습니다. */}
        {eventInfo.title && (
          <h2 style={{ fontSize: "50px", fontWeight: "900", marginBottom: "80px" }}>{eventInfo.title}</h2>
        )}
        
        {/* 💡 설명 데이터가 있을 때만 렌더링됩니다. */}
        {eventInfo.desc && (
          <p style={{ fontSize: "15px", lineHeight: "1.8", color: "#000", whiteSpace: "pre-line", fontWeight: "500" }}>
            {eventInfo.desc}
          </p>
        )}
      </div>

      {/* 4. 쿠폰팩 박스 통이미지 (두 번째 빨간 동그라미 구역) */}
      {/* 💡 쿠폰 사진 데이터가 있을 때만 회색 배경 박스를 그립니다. */}
      {eventInfo.couponBoxImg && (
        <div style={{ width: "950px", margin: "0 auto", backgroundColor: "#f5f5f5", minHeight: "500px", marginBottom: "220px" }}>
          <img src={process.env.PUBLIC_URL +eventInfo.couponBoxImg} alt="coupon pack" style={{ width: "100%", display: "block" }} />
        </div>
      )}

      {/* 5. 하단 전체 상품 보러가기 버튼 (유지) */}
      <div style={{ textAlign: "center", marginTop: "60px" }}>
        <button style={{ backgroundColor: "#000", color: "#fff", border: "none", padding: "16px 48px", fontSize: "16px", fontWeight: "700", cursor: "pointer", lineHeight: "1.4", borderRadius: "3px" }}>
          전체 상품<br/>보러가기
        </button>
      </div>

    </div>
  );
};

export default EventTemplate;