import React from "react";
import { Link } from "react-router-dom";

// 💡 items 를 받아옵니다.
const NewArrivals = ({ items }) => {
  return (
    <section style={{ width: "100%", marginTop: "60px", marginBottom: "60px" }}>
      <div style={{ maxWidth: "97%", margin: "0 auto" }}>
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "flex-end",
            marginBottom: "30px",
          }}
        >
          <div style={{ display: "flex", alignItems: "baseline", gap: "8px" }}>
            <h2
              style={{
                fontSize: "25px",
                fontWeight: "1000",
                margin: 0,
                color: "#000",
              }}
            >
              신상품
            </h2>
            <span style={{ fontSize: "15px", color: "#888" }}>
              4월 2일 13:50 기준
            </span>
          </div>
          <Link
            to="#"
            style={{
              fontSize: "11px",
              color: "#666",
              border: "1px solid #e0e0e0",
              padding: "6px 14px",
              borderRadius: "4px",
              textDecoration: "none",
            }}
          >
            모두 보기
          </Link>
        </div>

        {/* 💡 7열 -> 8열로 수정 완료 */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(8, 1fr)",
            gap: "15px",
          }}
        >
          {/* 💡 items 로 맵핑 */}
          {items &&
            items.map((item) => (
              <Link
                to="#"
                key={item.id}
                style={{
                  textDecoration: "none",
                  display: "flex",
                  flexDirection: "column",
                  minWidth: 0,
                }}
              >
                <div
                  style={{
                    backgroundColor: "#f6f6f6",
                    borderRadius: "6px",
                    aspectRatio: "4/5",
                    position: "relative",
                    overflow: "hidden",
                    padding: "0px",
                  }}
                >
                  <img
                    src={process.env.PUBLIC_URL +item.imgUrl}
                    alt={item.name}
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "contain",
                    }}
                    onMouseEnter={(e) => {
                      if (item.hoverImgUrl)
                        e.currentTarget.src = process.env.PUBLIC_URL + item.hoverImgUrl;
                    }}
                    onMouseLeave={(e) => {
                      if (item.hoverImgUrl) e.currentTarget.src = process.env.PUBLIC_URL + item.imgUrl;
                    }}
                  />
                  <i
                    className="fa-regular fa-bookmark"
                    style={{
                      position: "absolute",
                      top: "12px",
                      right: "12px",
                      fontSize: "18px",
                      color: "#ccc",
                      cursor: "pointer",
                    }}
                  ></i>
                </div>
                <div style={{ marginTop: "12px" }}>
                  <div
                    style={{
                      fontSize: "15px",
                      color: "#888",
                      marginBottom: "5px",
                      fontWeight: "400",
                    }}
                  >
                    {item.brand}
                  </div>
                  <div
                    style={{
                      fontSize: "14px",
                      color: "#111",
                      lineHeight: "1.4",
                      whiteSpace: "nowrap",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      marginBottom: "14px",
                      fontWeight: "400",
                    }}
                  >
                    {item.name}
                  </div>
                  <div
                    style={{
                      fontSize: "16.5px",
                      color: "#111",
                      fontWeight: "405",
                      marginTop: "6px",
                      marginBottom: "60px",
                    }}
                  >
                    {item.price}
                  </div>
                </div>
              </Link>
            ))}
        </div>
      </div>
    </section>
  );
};

export default NewArrivals;
