import React from "react";
import { Link } from "react-router-dom";

const MDPick = ({ items1, items2 }) => {
  return (
    <section style={{ width: "100%", backgroundColor: "#fff", paddingTop: "60px" }}>
      <div style={{ maxWidth: "97%", margin: "0 auto", marginBottom: "25px" }}>
        <h2 style={{ fontSize: "24px", fontWeight: "900", margin: 0, color: "#000", marginBottom: "29px" }}>
          MD 추천 기획
        </h2>
      </div>
      <div style={{ width: "100%", backgroundColor: "#f1f1f1", padding: "40px 0" }}>
        <div style={{ maxWidth: "96%", margin: "0 auto" }}>
          
          {/* 첫 번째 기획전 */}
          <div>
            <div style={{ marginBottom: "15px" }}>
              <div style={{ fontSize: "16px", fontWeight: "600", color: "#000", marginBottom: "10px", marginTop: "-17px" }}>
                새로운 계절을 위한 아우터
              </div>
              <div style={{ fontSize: "13px", color: "#aaa" }}>
                Outerwear for a New Season
              </div>
            </div>
            <div style={{ display: "flex", gap: "13.5px" }}>
              {items1 &&
                items1.map((item) => (
                  <Link
                    to="#"
                    key={item.id}
                    style={{
                      flex: "0 0 8.5%",
                      maxWidth: "140px",
                      backgroundColor: "#efefef",
                      aspectRatio: "93/118",
                      borderRadius: "2px",
                      overflow: "hidden",
                      display: "block",
                      marginBottom: "-2px",
                    }}
                  >
                    <img
                      src={process.env.PUBLIC_URL +item.imgUrl}
                      alt="MD추천"
                      style={{
                        width: "138px",
                        height: "100%",
                        objectFit: "contain",
                      }}
                    />
                  </Link>
                ))}
            </div>
          </div>

          <div style={{ height: "1px", backgroundColor: "#e5e5e5", margin: "40px 0" }}></div>

          {/* 두 번째 기획전 */}
          <div>
            <div style={{ marginBottom: "20px" }}>
              <div style={{ fontSize: "16px", fontWeight: "600", color: "#000", marginBottom: "8px", marginTop: "-17px" }}>
                로어즈 'Soft Utility' 26SS 컬렉션
              </div>
              <div style={{ fontSize: "13px", color: "#aaa" }}>
                LORES 'Soft Utility' 26SS Collection
              </div>
            </div>
            <div style={{ display: "flex", gap: "13.5px" }}>
              {items2 &&
                items2.map((item) => (
                  <Link
                    to="#"
                    key={item.id}
                    style={{
                      flex: "0 0 8.5%",
                      maxWidth: "140px",
                      backgroundColor: "#efefef",
                      aspectRatio: "93/118",
                      borderRadius: "2px",
                      overflow: "hidden",
                      display: "block",
                      marginBottom: "36px",
                    }}
                  >
                    <img
                      src={process.env.PUBLIC_URL +item.imgUrl}
                      alt="MD추천"
                      style={{
                        width: "138px",
                        height: "100%",
                        objectFit: "contain",
                      }}
                    />
                  </Link>
                ))}
            </div>
          </div>

        </div>
      </div>
    </section>
  );
};

export default MDPick;