              <button onClick={handleAddToCart} style={{height: "57px", borderRadius: "6px", flex: 1, backgroundColor: "#000", color: "#fff", border: "none", fontSize: "18px", fontWeight: "500", cursor: "pointer" }}>구매하기</button>
