import React from "react";
import { useParams } from "react-router-dom";
import CurationInfo from "../components/curation/CurationInfo"; // 👈 이름 변경 확인
import CurationItemList from "../components/curation/CurationItemList";
import curationData from "../data/curationData.json";

const CurationDetail = () => {
  const { id } = useParams();
  const data = curationData[id];

  if (!data) return <div style={{ padding: "100px", textAlign: "center" }}>데이터가 없습니다.</div>;

  return (
    <main style={{ width: "100%", paddingBottom: "100px" }}>
      {/* 바뀐 이름으로 연결 */}
      <CurationInfo info={data.headerInfo} />
      <CurationItemList products={data.products} />
    </main>
  );
};

export default CurationDetail;