import React from "react";

const Signup = () => {
  // 💡 반복되는 스타일을 변수로 빼서 코드를 깔끔하게 만듭니다.
  const sectionTitleStyle = { fontSize: "14px", fontWeight: "700", marginBottom: "15px", marginTop: "40px" };
  const labelStyle = { display: "block", fontSize: "13px", fontWeight: "700", marginBottom: "8px", marginTop: "20px", color: "#333" };
  const inputStyle = { width: "100%", padding: "14px", border: "1px solid #e5e5e5", borderRadius: "2px", boxSizing: "border-box", fontSize: "14px", outlineColor: "#000" };
  const checkWrapStyle = { display: "flex", alignItems: "center", marginBottom: "12px", fontSize: "13px", color: "#666" };
  const checkboxStyle = { marginRight: "8px", width: "16px", height: "16px", accentColor: "#000", cursor: "pointer" };

  return (
    <main className="page-transition" key="signup" style={{ display: "flex", justifyContent: "center", padding: "40px 20px 100px" }}>
      <div style={{ width: "100%", maxWidth: "460px" }}>
        
        {/* --- 1. 회원인증 영역 --- */}
        <div style={sectionTitleStyle}>회원인증</div>
        <div style={{ display: "flex", alignItems: "center", paddingBottom: "30px", borderBottom: "1px solid #eee" }}>
          <label style={{ display: "flex", alignItems: "center", fontSize: "13px", cursor: "pointer", marginRight: "15px" }}>
            <input type="radio" name="verify" defaultChecked style={{ marginRight: "8px", accentColor: "#000" }} />
            휴대폰인증
          </label>
          <button style={{ padding: "6px 12px", border: "1px solid #e5e5e5", backgroundColor: "#fff", fontSize: "12px", cursor: "pointer", borderRadius: "2px" }}>
            인증하기
          </button>
        </div>

        {/* --- 2. 기본정보 영역 --- */}
        <div style={sectionTitleStyle}>기본정보</div>

        <label style={labelStyle}>아이디 *</label>
        <input type="text" style={inputStyle} />

        <label style={labelStyle}>비밀번호 *</label>
        <input type="password" style={inputStyle} />

        <label style={labelStyle}>비밀번호 확인 *</label>
        <input type="password" style={inputStyle} />

        <label style={labelStyle}>이름 *</label>
        <input type="text" style={inputStyle} />

        {/* 주소 영역 */}
        <label style={labelStyle}>주소</label>
        <div style={{ display: "flex", gap: "10px", marginBottom: "10px" }}>
          <input type="text" placeholder="우편번호" style={{ ...inputStyle, flex: 1, marginTop: 0 }} readOnly />
          <button style={{ padding: "0 20px", border: "1px solid #333", backgroundColor: "#fff", fontSize: "13px", fontWeight: "600", cursor: "pointer", borderRadius: "2px" }}>
            주소검색
          </button>
        </div>
        <input type="text" placeholder="기본주소" style={{ ...inputStyle, marginBottom: "10px" }} readOnly />
        <input type="text" placeholder="나머지 주소(선택 입력 가능)" style={inputStyle} />

        {/* 일반전화 영역 */}
        <label style={labelStyle}>일반전화</label>
        <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
          <select style={{ ...inputStyle, width: "30%", marginTop: 0 }}>
            <option>02</option>
            <option>031</option>
            <option>032</option>
          </select>
          <span style={{ color: "#999" }}>-</span>
          <input type="text" style={{ ...inputStyle, flex: 1, marginTop: 0 }} />
          <span style={{ color: "#999" }}>-</span>
          <input type="text" style={{ ...inputStyle, flex: 1, marginTop: 0 }} />
        </div>

        {/* 휴대전화 영역 */}
        <label style={labelStyle}>휴대전화 *</label>
        <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
          <select style={{ ...inputStyle, width: "30%", marginTop: 0 }}>
            <option>010</option>
            <option>011</option>
          </select>
          <span style={{ color: "#999" }}>-</span>
          <input type="text" style={{ ...inputStyle, flex: 1, marginTop: 0 }} />
          <span style={{ color: "#999" }}>-</span>
          <input type="text" style={{ ...inputStyle, flex: 1, marginTop: 0 }} />
        </div>

        <label style={labelStyle}>이메일 *</label>
        <input type="email" style={{ ...inputStyle, marginBottom: "40px" }} />

        {/* --- 3. 서비스 이용 동의 영역 --- */}
        <div style={{ borderTop: "1px solid #eee", paddingTop: "30px" }}>
          <div style={sectionTitleStyle}>서비스 이용 동의</div>
          
          {/* 전체 동의 */}
          <label style={{ display: "flex", alignItems: "flex-start", marginBottom: "20px", cursor: "pointer" }}>
            <input type="checkbox" style={{ ...checkboxStyle, marginTop: "2px" }} />
            <div>
              <div style={{ fontSize: "14px", fontWeight: "700", color: "#000", marginBottom: "4px" }}>
                이용약관에 모두 동의합니다. (선택 정보 포함)
              </div>
              <div style={{ fontSize: "12px", color: "#666", fontWeight: "600" }}>
                이용약관 및 개인정보수집 및 이용에 모두 동의합니다.
              </div>
            </div>
          </label>

          <div style={{ borderTop: "1px solid #f5f5f5", paddingTop: "15px", marginBottom: "40px" }}>
            <label style={checkWrapStyle}>
              <input type="checkbox" style={checkboxStyle} />
              <span>[필수] <span style={{ textDecoration: "underline" }}>이용약관</span>에 동의합니다.</span>
            </label>
            <label style={checkWrapStyle}>
              <input type="checkbox" style={checkboxStyle} />
              <span>[필수] <span style={{ textDecoration: "underline" }}>개인정보 수집 및 이용</span>에 동의합니다.</span>
            </label>
            <label style={checkWrapStyle}>
              <input type="checkbox" style={checkboxStyle} />
              [선택] SMS 알림에 동의합니다.
            </label>
            <label style={checkWrapStyle}>
              <input type="checkbox" style={checkboxStyle} />
              [선택] 이메일 알림에 동의합니다.
            </label>
          </div>
        </div>

        {/* --- 4. 가입하기 버튼 --- */}
        <button style={{ 
          width: "100%", padding: "18px", backgroundColor: "#000", color: "#fff", border: "none", borderRadius: "2px", fontSize: "16px", fontWeight: "700", cursor: "pointer"
        }}>
          가입하기
        </button>

      </div>
    </main>
  );
};

export default Signup;