// 💡 1. useContext와 CartContext를 불러옵니다.
import React, { useState, useEffect, useContext } from "react";
import { Link, useLocation } from "react-router-dom";
import { CartContext } from "../context/CartContext";
import logoImg from "./logo.png";

const Header = () => {
  const [isHide, setIsHide] = useState(false);
  const location = useLocation();
  const currentPath = location.pathname;
  
  // 💡 2. 장바구니 데이터를 가져옵니다.
  const { cart } = useContext(CartContext);

  useEffect(() => {
    let lastScrollY = window.scrollY;
    let ticking = false;

    const handleScroll = () => {
      // 💡 렌더링 폭주를 막아주는 튼튼한 방패 (requestAnimationFrame)
      if (!ticking) {
        window.requestAnimationFrame(() => {
          const currentScrollY = window.scrollY;

          // 1. 화면 맨 위면 무조건 보여줌
          if (currentScrollY <= 10) {
            setIsHide(false);
          }
          // 2. 아래로 15px 이상 굴리면 얄짤없이 숨김
          else if (currentScrollY - lastScrollY > 15) {
            setIsHide(true);
          }
          // 3. 위로 15px 이상 올리면 얄짤없이 보여줌
          else if (lastScrollY - currentScrollY > 15) {
            setIsHide(false);
          }

          lastScrollY = currentScrollY;
          ticking = false;
        });
        ticking = true;
      }
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <header
      style={{
        position: "sticky",
        top: 0,
        zIndex: 1000,
        background: "#fff",
        padding: "16px 24px 0",
      }}
    >
      {/* --- 상단 영역 (로고, 메인 네비게이션, 우측 메뉴) --- */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          paddingBottom: "20px",
          backgroundColor: "#fff",
          position: "relative",
          zIndex: 2, // 지붕 역할
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "30px" }}>
          {/* 유저님이 커스텀하신 로고 부분 그대로 적용 */}
          <Link
            to="/"
            style={{
              display: "flex",
              alignItems: "center",
              textDecoration: "none",
            }}
          >
            <img
              src={logoImg}
              alt="HEIGHTS Logo"
              style={{
                height: "18px",
                display: "block",
                marginLeft: "10px",
                marginTop: "3px", // 중복된 marginTop을 하나로 합쳤습니다
              }}
            />
          </Link>

          {/* 유저님이 커스텀하신 네비게이션 간격 그대로 적용 */}
          <nav
            style={{
              display: "flex",
              gap: "12px",
              fontSize: "19.5px",
              fontWeight: "800",
              marginLeft: "-12px",
            }}
          >
            <Link
              to="/"
              style={{
                color: currentPath === "/" ? "#000" : "#ccc",
                fontWeight: currentPath === "/" ? "900" : "normal",
                textDecoration: "none",
                fontWeight: "600",
              }}
            >
              남성
            </Link>
            <Link
              to="/women"
              style={{
                color: currentPath === "/women" ? "#000" : "#ccc",
                fontWeight: currentPath === "/women" ? "900" : "normal",
                textDecoration: "none",
                fontWeight: "600",
              }}
            >
              여성
            </Link>
            <Link to="/" style={{ color: "#ccc", textDecoration: "none" }}>
              라이프
            </Link>
            <Link to="/" style={{ color: "#d0021b", textDecoration: "none" }}>
              세일
            </Link>
            <span style={{ color: "#eee" }}>|</span>
            <Link to="/" style={{ color: "#ccc", textDecoration: "none" }}>
              브랜드
            </Link>
          </nav>
        </div>

        {/* 우측 유틸리티 메뉴 */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "15px",
            fontSize: "14px",
            fontWeight: "700",
          }}
        >
          <Link to="#" style={{ color: "#000", textDecoration: "none" }}>
            큐레이션
          </Link>
          <Link to="#" style={{ color: "#000", textDecoration: "none" }}>
            매거진
          </Link>
          <span style={{ color: "#eee", fontWeight: "100" }}>|</span>

          <Link
            to="/login"
            style={{ color: "#000", textDecoration: "none", fontWeight: "500" }}
          >
            로그인
          </Link>

          <Link
            to="/signup"
            style={{ color: "#000", textDecoration: "none", fontWeight: "500" }}
          >
            회원가입
          </Link>

          <Link
            to="/cs"
            style={{ color: "#000", textDecoration: "none", fontWeight: "500" }}
          >
            고객센터
          </Link>

          <div
            style={{
              display: "flex",
              gap: "28px",
              fontSize: "18px",
              marginLeft: "10px",
              marginRight: "10px",
            }}
          >
            <Link to="#" style={{ color: "#000" }}>
              <i className="fa fa-search"></i>
            </Link>

            {/* 💡 3. 장바구니 아이콘 링크를 "/cart"로 바꾸고 숫자를 동기화했습니다. */}
            <Link to="/cart" style={{ color: "#000", position: "relative" }}>
              <i className="fa fa-shopping-bag"></i>
              <span
                style={{
                  position: "absolute",
                  top: "-6px",
                  right: "-8px",
                  background: "#000",
                  color: "#fff",
                  fontSize: "10px",
                  width: "16px",
                  height: "16px",
                  borderRadius: "50%",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontWeight: "bold",
                }}
              >
                {/* 💡 담긴 상품의 개수가 실시간으로 표시됩니다. */}
                {cart.length}
              </span>
            </Link>
          </div>
        </div>
      </div>

      {/* --- 하단 영역 (서브 메뉴) --- */}
      {/* 💡 덜덜이 해결 핵심: 껍데기(높이 제어)와 알맹이(글자 이동)를 분리했습니다! */}
      <div
        style={{
          position: "relative",
          zIndex: 1,
          overflow: "hidden", // 삐져나오는 글자 싹둑
          // 유저님의 고급스러운 속도 그대로 적용
          transition: "max-height 0.4s cubic-bezier(0.25, 0.8, 0.25, 1)",
          maxHeight: isHide ? "0px" : "40px", // 껍데기 높이를 부드럽게 줄임
        }}
      >
        <div
          style={{
            display: "flex",
            gap: "21px",
            fontSize: "16px",
            fontWeight: "510",
            marginLeft: "13px",
            paddingBottom: "20px", // 여백은 알맹이에 둬서 껍데기 줄어들 때 같이 빨려 올라가게 함
            // 유저님의 고급스러운 속도 그대로 적용
            transition: "all 0.4s cubic-bezier(0.25, 0.8, 0.25, 1)",
            opacity: isHide ? 0 : 1,
            transform: isHide ? "translateY(-20px)" : "translateY(0)",
          }}
        >
          {["추천", "의류", "모자", "악세서리", "가방", "신발", "랭킹"].map(
            (menu, idx) => (
              <Link
                key={idx}
                to="#"
                style={{
                  color: "#000",
                  textDecoration: "none",
                }}
              >
                {menu}
              </Link>
            ),
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;