import React, { useState } from "react"; // 💡 useState를 불러옵니다
import ProductCard from "./ProductCard";

const DetailGrid = ({ products }) => {
  // 💡 현재 선택된 정렬 기준을 저장하는 상태 (기본값: 'new')
  const [sortType, setSortType] = useState("new");

  // 💡 정렬 로직
  // 원본 데이터를 건드리지 않기 위해 [...products]로 복사해서 사용합니다.
  const sortedProducts = [...products].sort((a, b) => {
    // 1. 가격에서 숫자만 뽑아내는 마법의 주문 (예: "15,000 원" -> 15000)
    const priceA = parseInt(a.price.replace(/[^0-9]/g, ""), 10);
    const priceB = parseInt(b.price.replace(/[^0-9]/g, ""), 10);

    if (sortType === "low") {
      return priceA - priceB; // 낮은 가격순
    } else if (sortType === "high") {
      return priceB - priceA; // 높은 가격순
    }
    // 'new' (신상품순) 일 때는 원래 순서 유지
    return 0; 
  });

  return (
    <>
      {/* 1. 상품 정렬 필터 */}
      <div style={{ display: "flex", justifyContent: "flex-end", fontSize: "12px", color: "#999", marginBottom: "20px" }}>
        
        {/* 신상품순 버튼 */}
        <span 
          onClick={() => setSortType("new")}
          style={{ 
            cursor: "pointer", 
            color: sortType === "new" ? "#000" : "#999", 
            fontWeight: sortType === "new" ? "bold" : "normal" 
          }}
        >
          신상품순
        </span>
        <span style={{ margin: "0 8px" }}>|</span>
        
        {/* 낮은가격순 버튼 */}
        <span 
          onClick={() => setSortType("low")}
          style={{ 
            cursor: "pointer", 
            color: sortType === "low" ? "#000" : "#999", 
            fontWeight: sortType === "low" ? "bold" : "normal" 
          }}
        >
          낮은가격순
        </span>
        <span style={{ margin: "0 8px" }}>|</span>
        
        {/* 높은가격순 버튼 */}
        <span 
          onClick={() => setSortType("high")}
          style={{ 
            cursor: "pointer", 
            color: sortType === "high" ? "#000" : "#999", 
            fontWeight: sortType === "high" ? "bold" : "normal" 
          }}
        >
          높은가격순
        </span>
      </div>

      {/* 2. 상품 바둑판 (5열) */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(5, 1fr)",
          columnGap: "16px",
          rowGap: "40px",
          marginBottom: "100px",
          width: "100%",  
        }}
      >
        {/* 💡 기존 products 대신, 정렬이 완료된 sortedProducts를 화면에 뿌립니다 */}
        {sortedProducts.map((item) => (
          <ProductCard key={item.id} item={item} />
        ))}
      </div>
    </>
  );
};

export default DetailGrid;