import React from "react";
import { Link } from "react-router-dom";

// 💡 1. brands 를 받아옵니다.
const TrendingBrands = ({ brands }) => {
  return (
    <section
      style={{ width: "100%", marginTop: "100px", marginBottom: "100px" }}
    >
      <div style={{ maxWidth: "97%", margin: "0 auto" }}>
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "50px",
          }}
        >
          <h2
            style={{
              fontSize: "25px",
              fontWeight: "625",
              margin: 0,
              color: "#000",
            }}
          >
            하이츠가 주목하는 브랜드
          </h2>
          <Link
            to="#"
            style={{
              fontSize: "11px",
              color: "#666",
              border: "1px solid #e0e0e0",
              padding: "7px 10px",
              borderRadius: "4px",
              textDecoration: "none",
            }}
          >
            모두 보기
          </Link>
        </div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
          {/* 💡 2. 길었던 가짜 배열을 지우고 brands.map 으로 변경 */}
          {brands &&
            brands.map((brand) => (
              <Link
                to="#"
                key={brand.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "8px",
                  padding: "6px 18px 6px 6px",
                  border: "1px solid #eaeaea",
                  borderRadius: "50px",
                  textDecoration: "none",
                  color: "#111",
                }}
              >
                <img
                  src={process.env.PUBLIC_URL + brand.imgUrl}
                  alt={brand.en}
                  style={{
                    width: "43px",
                    height: "43px",
                    borderRadius: "50%",
                    objectFit: "cover",
                  }}
                />
                <span style={{ fontSize: "15px" }}>
                  <span style={{ fontWeight: "400", color: "#222" }}>
                    {brand.en}
                  </span>{" "}
                  <span style={{ color: "#111", fontWeight: "515" }}>
                    {brand.ko}
                  </span>
                </span>
              </Link>
            ))}
        </div>
      </div>
    </section>
  );
};

export default TrendingBrands;
