import React from "react";
import Hero from "../components/home/Hero";
import Curation from "../components/home/Curation";
import Spotlight from "../components/home/Spotlight";
import TrendingBrands from "../components/home/TrendingBrands";
import NewArrivals from "../components/home/NewArrivals";
import Ranking from "../components/home/Ranking";
import MDPick from "../components/home/MDPick";
import Magazine from "../components/home/Magazine";
import ReleaseSchedule from "../components/home/ReleaseSchedule";

// 💡 여성용 전용 데이터를 불러옵니다.
import womenData from "../data/womenData.json";

const Women = () => {
  return (
    <main className="page-transition" key="women">
      {/* 💡 Home.js와 완벽하게 동일한 순서, 동일한 이름표로 데이터를 넘깁니다 */}
      <Hero
        topBanners={womenData.heroTop || []}
        bottomBanners={womenData.heroBottom || []}
      />
      <Curation items={womenData.curation || []} />
      <Spotlight items={womenData.spotlight || []} />
      <TrendingBrands brands={womenData.trendingBrands || []} />
      <NewArrivals items={womenData.newArrivals || []} />
      <Ranking
        rankingItems={womenData.ranking || []}
        slideItems={womenData.slides || []}
      />
      <MDPick
        items1={womenData.mdPick?.section1 || []}
        items2={womenData.mdPick?.section2 || []}
      />
      <Magazine items={womenData.magazine || []} />
      <ReleaseSchedule schedules={womenData.releaseSchedule || []} />
    </main>
  );
};

export default Women;