import React, { useState } from "react";
import { Link } from "react-router-dom"; // 💡 1. Link 기능 불러오기

const ProductCard = ({ item }) => {
  // 💡 이미지가 다 다운로드되었는지 확인하는 스위치!
  const [isLoaded, setIsLoaded] = useState(false);

  return (
    // 💡 2. 가장 바깥쪽을 Link로 싹 감싸고, 도착지를 /product/아이디 로 설정!
    <Link to={`/product/${item.id}`} key={item.id} style={{ textDecoration: "none", color: "inherit", display: "block" }}>
      
      <div style={{ cursor: "pointer" }}>
        <div style={{ width: "100%", aspectRatio: "1/1", backgroundColor: "#f0f0f0", marginBottom: "12px", position: "relative" }}>
          
          {/* 1. 로딩 전: 예쁜 회색 빈 박스 (스켈레톤) */}
          {!isLoaded && (
            <div style={{ width: "100%", height: "100%", backgroundColor: "#e8e8e8" }} />
          )}

          {/* 2. 실제 이미지: 다 다운받아지면 스르륵 나타납니다 */}
          <img 
            src={process.env.PUBLIC_URL +item.imgUrl} 
            alt={item.name} 
            loading="lazy" 
            onLoad={() => setIsLoaded(true)} // 💡 다운로드 완료 시 스위치 ON!
            style={{ 
              width: "100%", 
              height: "100%", 
              objectFit: "cover",
              opacity: isLoaded ? 1 : 0, // 로딩 완료 전엔 투명하게
              transition: "opacity 0.4s ease-in-out", // 부드럽게 나타나는 애니메이션
              position: isLoaded ? "static" : "absolute", 
              top: 0, left: 0
            }} 
          />
          <i className="fa-regular fa-bookmark" style={{ position: "absolute", top: "10px", right: "10px", fontSize: "16px", color: "#fff", textShadow: "0 0 2px rgba(0,0,0,0.3)" }}></i>
        </div>
        
        {/* 텍스트 영역 */}
        <div style={{ padding: "0 2px" }}>
          <div style={{ fontSize: "11px", color: "#999", marginBottom: "4px" }}>{item.brand}</div>
          <div style={{ fontSize: "12px", color: "#111", marginBottom: "6px", fontWeight: "500", lineHeight: "1.3" }}>{item.name}</div>
          <div style={{ fontSize: "13px", fontWeight: "800", color: "#000" }}>{item.price}</div>
        </div>
      </div>

    </Link>
  );
};

export default ProductCard;