import { useEffect } from "react";
import { useLocation } from "react-router-dom";

export default function ScrollToTop() {
  const { pathname } = useLocation(); // 현재 주소창의 경로를 가져옵니다.

  useEffect(() => {
    // 주소(pathname)가 바뀔 때마다 화면 맨 위(0, 0)로 스크롤을 올립니다!
    window.scrollTo(0, 0);
  }, [pathname]);

  return null; // 화면에 그릴 건 없으므로 null 반환
}