import React, { useState } from "react";
// 💡 리액트 아이콘을 사용합니다 (없으면 npm install react-icons)
import { FiHome, FiMessageCircle, FiSettings, FiX, FiGlobe, FiBell } from "react-icons/fi";

const ChatBot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState("home"); // home, chat, settings

  // 1. 홈 탭 내용
  const renderHome = () => (
    <div style={{ padding: "20px", backgroundColor: "#f8f9fa", height: "100%", boxSizing: "border-box", overflowY: "auto" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "20px" }}>
        <div style={{ width: "40px", height: "40px", borderRadius: "50%", backgroundColor: "#fff", display: "flex", justifyContent: "center", alignItems: "center", fontWeight: "900", fontSize: "12px", border: "1px solid #eee" }}>H.</div>
        <div>
          <h3 style={{ margin: 0, fontSize: "16px", fontWeight: "900" }}>HEIGHTS</h3>
          <p style={{ margin: 0, fontSize: "12px", color: "#888", display: "flex", alignItems: "center", cursor: "pointer" }}>운영시간 보기 {'>'}</p>
        </div>
      </div>

      <div style={{ backgroundColor: "#fff", borderRadius: "15px", padding: "20px", boxShadow: "0 2px 10px rgba(0,0,0,0.02)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "15px" }}>
           <div style={{ width: "30px", height: "30px", borderRadius: "50%", backgroundColor: "#fff", display: "flex", justifyContent: "center", alignItems: "center", fontWeight: "900", fontSize: "10px", border: "1px solid #eee" }}>H.</div>
           <span style={{ fontWeight: "700", fontSize: "14px" }}>HEIGHTS</span>
        </div>
        <p style={{ fontSize: "15px", lineHeight: "1.5", margin: "0 0 20px 0", fontWeight: "500" }}>
          안녕하세요 고객님<br/>
          Heights. 입니다.<br/><br/>
          문의 내용을 선택해주세요 😊
        </p>
        <button style={{ width: "100%", padding: "12px", backgroundColor: "#f4f4f4", border: "none", borderRadius: "10px", color: "#888", fontWeight: "600", cursor: "pointer", display: "flex", justifyContent: "center", alignItems: "center", gap: "5px" }}>
          ☕ 오후 2:00부터 운영해요
        </button>
      </div>
      <div style={{ textAlign: "center", marginTop: "20px" }}>
        <span style={{ fontSize: "11px", color: "#bbb" }}>💬 채널톡 이용중</span>
      </div>
    </div>
  );

  // 2. 대화 탭 내용
  const renderChat = () => (
    <div style={{ display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", height: "100%" }}>
      <div style={{ width: "60px", height: "60px", borderRadius: "50%", backgroundColor: "#f0f0f0", display: "flex", justifyContent: "center", alignItems: "center", marginBottom: "20px" }}>
        <FiMessageCircle size="30" color="#ccc" />
      </div>
      <p style={{ color: "#888", fontSize: "15px", fontWeight: "500" }}>대화를 시작해보세요</p>
    </div>
  );

  // 3. 설정 탭 내용
  const renderSettings = () => (
    <div style={{ padding: "20px", height: "100%", boxSizing: "border-box" }}>
      <h2 style={{ fontSize: "20px", fontWeight: "800", marginTop: 0, marginBottom: "30px" }}>설정</h2>
      
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginBottom: "40px" }}>
        <div style={{ width: "60px", height: "60px", borderRadius: "50%", backgroundColor: "#60c6ff", display: "flex", justifyContent: "center", alignItems: "center", fontSize: "30px", marginBottom: "10px" }}>👑</div>
        <h3 style={{ margin: "0 0 5px 0", fontSize: "16px", color: "#888" }}>이름</h3>
        <p style={{ margin: "0 0 15px 0", fontSize: "13px", color: "#aaa" }}>연락처 정보</p>
        <button style={{ padding: "8px 16px", backgroundColor: "#f4f4f4", border: "none", borderRadius: "20px", fontSize: "12px", fontWeight: "600", color: "#666", cursor: "pointer" }}>📝 정보 수정하기</button>
      </div>

      <p style={{ fontSize: "12px", color: "#aaa", marginBottom: "10px" }}>상담 환경</p>
      
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "15px 0", borderBottom: "1px solid #f0f0f0" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "10px", fontSize: "15px", color: "#333", fontWeight: "500" }}><FiGlobe size="18"/> 언어</div>
        <span style={{ fontSize: "14px", color: "#888", cursor: "pointer" }}>한국어 {'>'}</span>
      </div>

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "15px 0", borderBottom: "1px solid #f0f0f0" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "10px", fontSize: "15px", color: "#333", fontWeight: "500" }}><FiMessageCircle size="18"/> 메시지 번역 표시</div>
        <div style={{ width: "45px", height: "24px", backgroundColor: "#00de5a", borderRadius: "15px", position: "relative", cursor: "pointer" }}>
          <div style={{ width: "20px", height: "20px", backgroundColor: "#fff", borderRadius: "50%", position: "absolute", right: "2px", top: "2px" }} />
        </div>
      </div>

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "15px 0" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "10px", fontSize: "15px", color: "#333", fontWeight: "500" }}><FiBell size="18"/> 알림음</div>
        <div style={{ width: "45px", height: "24px", backgroundColor: "#00de5a", borderRadius: "15px", position: "relative", cursor: "pointer" }}>
          <div style={{ width: "20px", height: "20px", backgroundColor: "#fff", borderRadius: "50%", position: "absolute", right: "2px", top: "2px" }} />
        </div>
      </div>
      <p style={{ textAlign: "right", fontSize: "11px", color: "#ccc", marginTop: "10px" }}>v17.1.4</p>
    </div>
  );

  return (
    <>
      {/* 💡 핵심! position: fixed로 화면 우측 하단에 딱 고정시킵니다. */}
      {/* 열렸을 때 보이는 챗봇 창 */}
      {isOpen && (
        <div style={{ position: "fixed", bottom: "100px", right: "30px", width: "360px", height: "650px", backgroundColor: "#fff", borderRadius: "25px", boxShadow: "0 10px 30px rgba(0,0,0,0.15)", zIndex: 9999, display: "flex", flexDirection: "column", overflow: "hidden" }}>
          
          {/* 본문 영역 (스크롤 가능) */}
          <div style={{ flex: 1, overflowY: "auto" }}>
            {activeTab === "home" && renderHome()}
            {activeTab === "chat" && renderChat()}
            {activeTab === "settings" && renderSettings()}
          </div>

          {/* 하단 네비게이션 바 */}
          <div style={{ height: "65px", display: "flex", borderTop: "1px solid #f0f0f0", backgroundColor: "#fff" }}>
            <button onClick={() => setActiveTab("home")} style={{ flex: 1, background: "none", border: "none", display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", gap: "5px", cursor: "pointer", color: activeTab === "home" ? "#111" : "#aaa" }}>
              <FiHome size="22" color={activeTab === "home" ? "#111" : "#aaa"} />
              <span style={{ fontSize: "11px", fontWeight: activeTab === "home" ? "700" : "500" }}>홈</span>
            </button>
            <button onClick={() => setActiveTab("chat")} style={{ flex: 1, background: "none", border: "none", display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", gap: "5px", cursor: "pointer", color: activeTab === "chat" ? "#111" : "#aaa" }}>
              <FiMessageCircle size="22" color={activeTab === "chat" ? "#111" : "#aaa"} />
              <span style={{ fontSize: "11px", fontWeight: activeTab === "chat" ? "700" : "500" }}>대화</span>
            </button>
            <button onClick={() => setActiveTab("settings")} style={{ flex: 1, background: "none", border: "none", display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", gap: "5px", cursor: "pointer", color: activeTab === "settings" ? "#111" : "#aaa" }}>
              <FiSettings size="22" color={activeTab === "settings" ? "#111" : "#aaa"} />
              <span style={{ fontSize: "11px", fontWeight: activeTab === "settings" ? "700" : "500" }}>설정</span>
            </button>
          </div>
        </div>
      )}

      {/* 우측 하단 동그란 플로팅 버튼 (FAB) */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        style={{
          position: "fixed", bottom: "30px", right: "30px", width: "80px", height: "80px", 
          borderRadius: "50%", backgroundColor: isOpen ? "#fff" : "#000", 
          color: isOpen ? "#000" : "#fff", border: "1px solid #eee", 
          boxShadow: "0 5px 15px rgba(0,0,0,0.1)", zIndex: 10000, 
          cursor: "pointer", display: "flex", justifyContent: "center", alignItems: "center",
          fontSize: isOpen ? "24px" : "28px", fontWeight: "900", transition: "all 0.3s"
        }}
      >
        {/* 열려있으면 X 아이콘, 닫혀있으면 H. 로고 */}
        {isOpen ? (<FiX />
        ) : (
          <img 
            src={process.env.PUBLIC_URL +"/images/logo/mainlogo.jpg"} /* 💡 이 부분을 실제 이미지 경로로 변경하세요 */
            alt="chat-logo" 
            style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }} 
          />
        )}
      </button>
    </>
  );
};

export default ChatBot;