import React, { useState } from "react";

const TopBar = () => {
  // X 버튼을 누르면 배너가 닫히도록 상태 관리
  const [isBlackVisible, setIsBlackVisible] = useState(true);
  const [isWhiteVisible, setIsWhiteVisible] = useState(true);

  return (
    <>
      {/* 1. 상단 검은색 배너 */}
      {isBlackVisible && (
        <div
          style={{
            background: "#000",
            color: "#fff",
            padding: "14px 24px",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            fontSize: "14px",
            fontWeight: "700",
            letterSpacing: "-0.5px",
          }}
        >
          <span>봄 시즌 아이템 캠페인 : 최대 80% 할인 + 18% 3종 쿠폰팩</span>
          <button
            onClick={() => setIsBlackVisible(false)}
            style={{
              background: "none",
              border: "none",
              color: "#fff",
              cursor: "pointer",
              fontSize: "14px",
            }}
          >
            <i className="fa fa-times"></i>
          </button>
        </div>
      )}

      
    </>
  );
};

export default TopBar;
