import React, { useEffect } from "react";
import { useParams } from "react-router-dom"; // 💡 1. useParams 불러오기 (이게 없으면 에러가 납니다!)
import menHeroData from "../data/menHeroData.json";
import BrandHeader from "../components/detail/BrandHeader";
import DetailGrid from "../components/detail/DetailGrid";
import EventTemplate from "../components/detail/EventTemplate";
import womenHeroData from "../data/womenHeroData.json";


const Detail = () => {
  // 배너 누르고 들어왔을 때 스크롤이 중간에 걸려있는 버그 방지
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);
  
  const { brandId } = useParams();
 const currentBrandData = 
    (Array.isArray(menHeroData) && menHeroData.find((item) => String(item.id) === String(brandId))) || 
    (Array.isArray(womenHeroData) && womenHeroData.find((item) => String(item.id) === String(brandId)));
  
  if (!currentBrandData) {
    return <div style={{ padding: "100px", textAlign: "center" }}>등록된 브랜드 데이터가 없습니다.</div>;
  }

  return (
    <main
      className="page-transition"
      key={`detail-${brandId}`} // 💡 2. 키값을 동적으로 변경해야 다른 배너 클릭 시 화면이 새로고침됩니다.
      style={{
        padding: "40px 20px",
        maxWidth: "2000px", // 유저님이 넓게 설정하신 화면 크기 유지 (CSS 건드리지 않음!)
        margin: "0 auto",
        boxSizing: "border-box",
      }}
    >
      {currentBrandData.type === "event" ? (
        <EventTemplate eventInfo={currentBrandData.eventInfo} />
      ) : (
        <>
          {/* 💡 3. brandData가 아니라, 위에서 찾은 currentBrandData를 넣어줘야 클릭한 브랜드로 바뀝니다! */}
          <BrandHeader brandInfo={currentBrandData.brandInfo} ranking={currentBrandData.ranking} />
          
          {/* 💡 여기도 마찬가지로 currentBrandData 적용 */}
          <DetailGrid products={currentBrandData.products} />
        </>
      )}
      
    </main>
  );
};

export default Detail;