import React from "react";

const BrandHeader = ({ brandInfo, ranking }) => {
  return (
    <div
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "stretch",
        gap: "30px",
        marginBottom: "50px",
        marginTop: "-50px", // 💡 유저님이 수정한 위로 당기는 CSS!
      }}
    >
      {/* 왼쪽: 프로필 이미지 및 브랜드 정보 */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
        <img
          src={process.env.PUBLIC_URL +brandInfo.logo}
          alt="brand logo"
          style={{ width: "70px", height: "70px", borderRadius: "50%", objectFit: "contain" ,marginBottom: "20px",marginTop: "10px" }}
        />
        <h2 style={{ fontSize: "22px", fontWeight: "900", marginBottom: "12px", letterSpacing: "-0.5px" }}>
          {brandInfo.name}
        </h2>
        <p style={{ fontSize: "13px", color: "#333", lineHeight: "1.6", whiteSpace: "pre-line", fontWeight: "500" }}>
          {brandInfo.description}
        </p>
      </div>

      {/* 가운데: 인기 랭킹 리스트 */}
      <div style={{ width: "350px", display: "flex", flexDirection: "column", justifyContent: "center" }}>
        {ranking.map((rankItem, index) => (
          <div
            key={rankItem.id}
            style={{
              display: "flex",
              alignItems: "center",
              gap: "15px",
              padding: "12px 0",
              borderBottom: index !== 2 ? "1px solid #f0f0f0" : "none",
            }}
          >
            <span style={{ fontSize: "16px", fontWeight: "900", width: "15px", textAlign: "center" }}>
              {rankItem.id}
            </span>
            <img
              src={process.env.PUBLIC_URL +rankItem.thumb}
              alt={rankItem.name}
              style={{ width: "45px", height: "45px", objectFit: "cover", backgroundColor: "#f5f5f5" }}
            />
            <div style={{ display: "flex", flexDirection: "column" }}>
              <span style={{ fontSize: "11px", color: "#999", marginBottom: "2px" }}>{rankItem.brand}</span>
              <span style={{ fontSize: "13px", color: "#111", fontWeight: "500", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", width: "240px" }}>
                {rankItem.name}
              </span>
            </div>
          </div>
        ))}
      </div>

      {/* 오른쪽: 룩북 배너 */}
      <div style={{ width: "380px", height: "200px", position: "relative", borderRadius: "4px", overflow: "hidden" ,borderRadius: "10px",marginTop: "10px"}}>
        <img
          src={process.env.PUBLIC_URL +brandInfo.bannerImg}
          alt="lookbook banner"
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" , }} 
        />
        <div
          style={{
            position: "absolute",
            bottom: "15px",
            width: "100%",
            textAlign: "center",
            color: "#fff",
            fontSize: "14px",
            fontWeight: "700",
            textShadow: "0px 1px 4px rgba(0,0,0,0.6)",
          }}
        >
          {brandInfo.bannerText}
        </div>
      </div>
    </div>
  );
};

export default BrandHeader;