import React from "react";
import { Link } from "react-router-dom";

const FooterMen = () => {
  const categoryLinks = [
    { name: "신상품", list: ["전체"] },
    { name: "의류", list: ["전체", "아우터", "티셔츠", "탑", "팬츠"] },
    {
      name: "악세서리",
      list: [
        "전체",
        "모자",
        "지갑",
        "양말&언더웨어",
        "주얼리",
        "벨트",
        "장갑/스카프",
        "선글라스",
        "ETC",
      ],
    },
    { name: "신발", list: ["전체", "스니커즈", "샌들", "부츠"] },
    {
      name: "가방",
      list: [
        "전체",
        "백팩",
        "토트백",
        "숄더백",
        "캐리어",
        "파우치&케이스",
        "악세서리",
      ],
    },
    { name: "랭킹", list: ["전체", "의류", "악세서리", "가방", "신발"] },
  ];

  const images = [
    {
      label: "아우터",
      src:"/images/footer/footer-01.jpg",
    },
    {
      label: "탑",
      src:"/images/footer/footer-02.jpg",
    },
    {
      label: "하의",
      src:"/images/footer/footer-03.jpg",
    },
    {
      label: "모자",
      src: "/images/footer/footer-04.jpg",
    },
  ];

  return (
    <div
      style={{
        maxWidth: "96%",
        margin: "0 auto",
        padding: "40px 0",
        borderBottom: "1px solid #eaeaea",
        display: "flex",
        justifyContent: "space-between",
        marginTop: "-7px",
      }}
    >
      {/* 텍스트 메뉴 영역 */}
      <div style={{ flex: 1, paddingRight: "40px" }}>
        <div style={{ marginBottom: "33px" }}>
          <span
            style={{
              fontSize: "14px",
              fontWeight: "800",
              color: "#000",
              marginRight: "6px",
            }}
          >
            남성
          </span>
          <span style={{ fontSize: "14px", color: "#777" }}>전체 8,871개</span>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: "9px" }}>
          {categoryLinks.map((cat, idx) => (
            <div key={idx} style={{ display: "flex" }}>
              <div
                style={{
                  width: "80px",
                  flexShrink: 0,
                  fontSize: "13.8px",
                  color: "#777",
                  fontWeight: "450",
                  marginRight: "15.7px",
                }}
              >
                {cat.name}
              </div>
              <div style={{ display: "flex", gap: "10.5px", flexWrap: "wrap" }}>
                {cat.list.map((item, i) => (
                  <Link
                    to="#"
                    key={i}
                    style={{
                      fontSize: "13.5px",
                      color: i === 0 ? "#000" : "#000",
                      fontWeight: i === 0 ? "525" : "525",
                      textDecoration: "none",
                    }}
                  >
                    {item}
                  </Link>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* 이미지 썸네일 영역 */}
      <div style={{ display: "flex", gap: "15px" }}>
        {images.map((img, idx) => (
          <Link
            key={idx}
            to="#"
            style={{
              position: "relative",
              width: "163px",
              aspectRatio: "3/4",
              backgroundColor: "#e8e8e8",
              borderRadius: "3px",
              overflow: "hidden",
            }}
          >
            <img
              src={process.env.PUBLIC_URL +img.src}
              alt={img.label}
              style={{ width: "100%", height: "100%", objectFit: "contain" }}
            />
            <div
              style={{
                position: "absolute",
                top: 0,
                left: 0,
                width: "100%",
                height: "100%",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                color: "#fff",
                fontSize: "12px",
                fontWeight: "bold",
                textShadow: "0 0 4px rgba(0,0,0,0.5)",
              }}
            >
              {img.label}
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
};

export default FooterMen;
