// src/context/CartContext.js
import React, { createContext, useState } from 'react';

export const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState([]);

  // 1. 장바구니 담기 (이미 있으면 수량만 +1)
  const addToCart = (product) => {
    setCart((prev) => {
      const existingItem = prev.find(item => item.id === product.id);
      if (existingItem) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: (item.quantity || 1) + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1, checked: true }]; // 처음 담을 땐 수량 1개, 체크 활성화
    });
  };

  // 2. 삭제하기
  const removeFromCart = (id) => {
    setCart((prev) => prev.filter(item => item.id !== id));
  };

  // 3. 수량 증감 기능 (+, - 버튼)
  const updateQuantity = (id, amount) => {
    setCart((prev) => prev.map(item => {
      if (item.id === id) {
        const newQuantity = (item.quantity || 1) + amount;
        return { ...item, quantity: newQuantity > 0 ? newQuantity : 1 }; // 최소 수량 1개 유지
      }
      return item;
    }));
  };

  // 4. 개별 체크박스 토글
  const toggleCheck = (id) => {
    setCart((prev) => prev.map(item => item.id === id ? { ...item, checked: !item.checked } : item));
  };

  // 5. 전체선택 토글
  const toggleAllCheck = (isChecked) => {
    setCart((prev) => prev.map(item => ({ ...item, checked: isChecked })));
  };

  return (
    <CartContext.Provider value={{ cart, addToCart, removeFromCart, updateQuantity, toggleCheck, toggleAllCheck }}>
      {children}
    </CartContext.Provider>
  );
};