import React from "react";
// 💡 중요: 방금 만든 대형 상품 카드(CurationProductCard)를 불러옵니다.
import CurationProductCard from "./CurationProductCard"; 

const CurationItemList = ({ products }) => {
  return (
    // maxWidth를 조절하여 전체 리스트의 가로폭을 잡습니다.
    <section style={{ maxWidth: "800px", margin: "0 auto", padding: "0 20px" }}>
      <div style={{ 
        // 💡 핵심: display: "flex"와 "column"을 써서 상품들을 세로로 길게 한 줄로 나열합니다.
        display: "flex", 
        flexDirection: "column",
        gap: "0px" // 카드 자체에 margin이 있으므로 gap은 0으로 둡니다.
      }}>
        {products.map((item) => (
          // 💡 중요: 기존 ProductCard 대신 대형 카드(CurationProductCard)를 사용합니다.
          <CurationProductCard key={item.id} item={item} />
        ))}
      </div>
    </section>
  );
};

export default CurationItemList;