import React from "react";
import { Link } from "react-router-dom";

const Login = () => {
  return (
    <main
      className="page-transition"
      key="login"
      style={{
        display: "flex",
        justifyContent: "center",
        padding: "80px 20px",
        marginBottom: "100px",
      }}
    >
      <div style={{ width: "100%", maxWidth: "380px" }}>
        {/* 아이디 입력칸 */}
        <div style={{ marginBottom: "15px" }}>
          <label
            style={{
              display: "block",
              fontSize: "13px",
              fontWeight: "700",
              marginBottom: "8px",
              color: "#333",
            }}
          >
            아이디
          </label>
          <input
            type="text"
            placeholder="아이디"
            style={{
              width: "100%",
              padding: "14px",
              border: "1px solid #e5e5e5",
              borderRadius: "2px",
              boxSizing: "border-box",
              fontSize: "14px",
              outlineColor: "#000",
            }}
          />
        </div>

        {/* 비밀번호 입력칸 */}
        <div style={{ marginBottom: "20px" }}>
          <label
            style={{
              display: "block",
              fontSize: "13px",
              fontWeight: "700",
              marginBottom: "8px",
              color: "#333",
            }}
          >
            비밀번호
          </label>
          <input
            type="password"
            placeholder="패스워드"
            style={{
              width: "100%",
              padding: "14px",
              border: "1px solid #e5e5e5",
              borderRadius: "2px",
              boxSizing: "border-box",
              fontSize: "14px",
              outlineColor: "#000",
            }}
          />
        </div>

        {/* 아이디 저장 체크박스 */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            marginBottom: "25px",
          }}
        >
          <input
            type="checkbox"
            id="saveId"
            style={{
              marginRight: "8px",
              width: "16px",
              height: "16px",
              accentColor: "#000",
              cursor: "pointer",
            }}
          />
          <label
            htmlFor="saveId"
            style={{ fontSize: "13px", color: "#333", cursor: "pointer" }}
          >
            아이디 저장
          </label>
        </div>

        {/* 로그인 버튼 */}
        <button
          style={{
            width: "100%",
            padding: "16px",
            backgroundColor: "#000",
            color: "#fff",
            border: "none",
            borderRadius: "2px",
            fontSize: "15px",
            fontWeight: "700",
            cursor: "pointer",
            marginBottom: "30px",
          }}
        >
          로그인
        </button>

        {/* 아이디/비밀번호 찾기, 회원가입 링크 */}
        <div
          style={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            gap: "15px",
            fontSize: "13px",
            color: "#666",
            marginBottom: "40px",
          }}
        >
          <Link to="#" style={{ color: "#666", textDecoration: "none" }}>
            주문조회
          </Link>
          <span style={{ color: "#e5e5e5" }}>|</span>
          <Link to="#" style={{ color: "#666", textDecoration: "none" }}>
            아이디 찾기
          </Link>
          <span style={{ color: "#e5e5e5" }}>|</span>
          <Link to="#" style={{ color: "#666", textDecoration: "none" }}>
            비밀번호 찾기
          </Link>
          <span style={{ color: "#e5e5e5" }}>|</span>
          <Link
            to="/signup"
            style={{
              color: "#666",
              textDecoration: "none",
              fontWeight: "bold",
            }}
          >
            회원가입
          </Link>
        </div>

        {/* 소셜 로그인 구분선 */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            marginBottom: "20px",
          }}
        >
          <div
            style={{ flex: 1, height: "1px", backgroundColor: "#eee" }}
          ></div>
          <span style={{ padding: "0 15px", fontSize: "12px", color: "#999" }}>
            간편 로그인
          </span>
          <div
            style={{ flex: 1, height: "1px", backgroundColor: "#eee" }}
          ></div>
        </div>

        {/* 소셜 로그인 버튼들 (순서 유지, 텍스트/이모지 기반) */}
        <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
          <SocialButton
            icon="N"
            text="네이버 로그인"
            bgColor="#fff"
            textColor="#191919"
            borderColor="#e5e5e5"
          />
          <SocialButton
            icon="f"
            text="페이스북 로그인"
            bgColor="#fff"
            textColor="#191919"
            borderColor="#e5e5e5"
          />
          <SocialButton
            icon="G"
            text="구글 로그인"
            bgColor="#fff"
            textColor="#191919"
            borderColor="#e5e5e5"
          />
          <SocialButton
            icon="💬"
            text="카카오 로그인"
            bgColor="#fff"
            textColor="#191919"
            borderColor="#e5e5e5"
          />
        </div>
      </div>
    </main>
  );
};

// 💡 소셜 로그인 버튼 미니 컴포넌트 (텍스트/이모지 지원 하도록 수정)
const SocialButton = ({ icon, text, bgColor, textColor, borderColor }) => {
  return (
    <button
      style={{
        display: "flex",
        alignItems: "center",
        width: "100%",
        padding: "14px 20px",
        backgroundColor: bgColor,
        border: `1px solid ${borderColor}`,
        borderRadius: "4px",
        cursor: "pointer",
      }}
    >
      <span
        style={{
          fontSize: "16px",
          fontWeight: "bold",
          width: "30px",
          textAlign: "left",
          color: textColor,
        }}
      >
        {icon}
      </span>
      <span
        style={{
          flex: 1,
          textAlign: "left",
          fontSize: "14px",
          fontWeight: "600",
          color: textColor,
        }}
      >
        {text}
      </span>
      <span style={{ width: "30px" }}></span>
    </button>
  );
};

export default Login;
