import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";

// 💡 rankingItems와 slideItems를 받아옵니다.
const Ranking = ({ rankingItems, slideItems }) => {
  // 에러 방지를 위해 데이터가 없을 경우 빈 배열 세팅
  const safeSlides = slideItems || [];
  const [currentSlide, setCurrentSlide] = useState(0);

  // 3초마다 자동으로 다음 슬라이드로 넘어가는 로직
  useEffect(() => {
    if (safeSlides.length === 0) return;
    const timer = setInterval(() => {
      setCurrentSlide((prev) =>
        prev === safeSlides.length - 1 ? 0 : prev + 1,
      );
    }, 3000);
    return () => clearInterval(timer);
  }, [safeSlides.length]);

  const nextSlide = () =>
    setCurrentSlide((prev) => (prev === safeSlides.length - 1 ? 0 : prev + 1));
  const prevSlide = () =>
    setCurrentSlide((prev) => (prev === 0 ? safeSlides.length - 1 : prev - 1));

  // 랭킹 아이템을 그리는 공통 함수
  const renderRankingItem = (item) => (
    <Link
      to="#"
      key={item.id}
      style={{
        display: "flex",
        alignItems: "center",
        gap: "16px",
        padding: "12px 0",
        borderBottom: "1px solid #f0f0f0",
        textDecoration: "none",
      }}
    >
      <span
        style={{
          fontSize: "17px",
          fontWeight: "900",
          width: "16px",
          color: "#000",
          textAlign: "center",
        }}
      >
        {item.rank}
      </span>
      <div
        style={{
          width: "48px",
          height: "48px",
          backgroundColor: "#f9f9f9",
          borderRadius: "4px",
          overflow: "hidden",
          flexShrink: 0,
        }}
      >
        {/* 💡 JSON 속성명에 따라 imgUrl을 사용하도록 수정 (없으면 thumb) */}
        <img
          src={process.env.PUBLIC_URL + (item.imgUrl || item.thumb)}
          alt={item.name}
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
        />
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <span style={{ fontSize: "11px", color: "#888" }}>{item.brand}</span>
        <span
          style={{
            fontSize: "16px",
            color: "#111",
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
            fontWeight: "500",
          }}
        >
          {item.name}
        </span>
      </div>
    </Link>
  );

  return (
    <section style={{ width: "100%", marginTop: "60px", marginBottom: "60px" }}>
      {/* 💡 변경점 1: 우측 슬라이더가 더 넓어 보이도록 비율을 5.5 : 4.5로 조정 */}
      <div
        style={{
          maxWidth: "96.5%",
          margin: "0 auto",
          display: "grid",
          gridTemplateColumns: "5fr 5.2fr",
          gap: "60px",
        }}
      >
        {/* === 좌측: 랭킹 영역 === */}
        <div>
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "flex-end",
              marginBottom: "37px",
            }}
          >
            <div
              style={{ display: "flex", alignItems: "baseline", gap: "8px" }}
            >
              <h2
                style={{
                  fontSize: "27px",
                  fontWeight: "800",
                  margin: 0,
                  color: "#000",
                }}
              >
                랭킹
              </h2>
              <span style={{ fontSize: "15px", color: "#888" }}>
                4월 3일 12:45 기준
              </span>
            </div>
            <Link
              to="#"
              style={{
                fontSize: "11px",
                color: "#666",
                border: "1px solid #e0e0e0",
                padding: "6px 14px",
                borderRadius: "4px",
                textDecoration: "none",
              }}
            >
              모두 보기
            </Link>
          </div>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "0 40px",
            }}
          >
            {/* 💡 rankingItems 데이터 적용 */}
            <div>
              {rankingItems && rankingItems.slice(0, 5).map(renderRankingItem)}
            </div>
            <div>
              {rankingItems && rankingItems.slice(5, 10).map(renderRankingItem)}
            </div>
          </div>
        </div>

        {/* === 우측: 슬라이더 영역 === */}
        {/* 💡 변경점 2: alignSelf로 세로 늘어남 방지, aspectRatio로 가로가 긴 비율 강제 고정 */}
        <div
          style={{
            position: "relative",
            overflow: "hidden",
            borderRadius: "5px",
            display: "flex",
            alignItems: "center",
            backgroundColor: "#000",
            alignSelf: "start",
            aspectRatio: "21/10",
            width: "99%",
            height: "340px",
          }}
        >
          <div
            style={{
              display: "flex",
              width: "1500px",
              height: "340px",
              transform: `translateX(-${currentSlide * 100}%)`,
              transition: "transform 0.5s ease-in-out",
            }}
          >
            {/* 💡 safeSlides 데이터 적용 */}
            {safeSlides.map((slide, idx) => (
              <img
                key={idx}
                src={process.env.PUBLIC_URL + (slide?.imgUrl || slide)} // JSON이 객체일 경우 imgUrl, 문자열일 경우 slide 자체
                alt={`배너 ${idx + 1}`}
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                  flexShrink: 0,
                }}
              />
            ))}
          </div>

          <button
            onClick={prevSlide}
            style={{
              position: "absolute",
              left: "10px",
              top: "50%",
              transform: "translateY(-50%)",
              backgroundColor: "rgba(0,0,0,0.5)",
              color: "#fff",
              border: "none",
              width: "32px",
              height: "32px",
              cursor: "pointer",
              zIndex: 10,
            }}
          >
            <i className="fa fa-chevron-left" style={{ fontSize: "12px" }}></i>
          </button>
          <button
            onClick={nextSlide}
            style={{
              position: "absolute",
              right: "10px",
              top: "50%",
              transform: "translateY(-50%)",
              backgroundColor: "rgba(0,0,0,0.5)",
              color: "#fff",
              border: "none",
              width: "32px",
              height: "32px",
              cursor: "pointer",
              zIndex: 10,
            }}
          >
            <i className="fa fa-chevron-right" style={{ fontSize: "12px" }}></i>
          </button>

          <div
            style={{
              position: "absolute",
              bottom: "16px",
              left: "0",
              right: "0",
              display: "flex",
              justifyContent: "center",
              gap: "8px",
              zIndex: 10,
            }}
          >
            {safeSlides.map((_, idx) => (
              <div
                key={idx}
                onClick={() => setCurrentSlide(idx)}
                style={{
                  width: "6px",
                  height: "6px",
                  borderRadius: "50%",
                  cursor: "pointer",
                  backgroundColor:
                    currentSlide === idx ? "#fff" : "rgba(255,255,255,0.4)",
                  transition: "background-color 0.3s",
                }}
              />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Ranking;
