// src/pages/Cart.js
import React, { useContext } from "react";
import { CartContext } from "../context/CartContext";

const Cart = () => {
  const { cart, removeFromCart, updateQuantity, toggleCheck, toggleAllCheck } = useContext(CartContext);

  // 💡 핵심 기능: "133,200 원" 같은 문자열에서 숫자만 쏙 뽑아내는 계산기
  const parsePrice = (priceStr) => {
    if (!priceStr) return 0;
    return parseInt(priceStr.replace(/[^0-9]/g, ""), 10); // 쉼표와 글자 제거
  };

  // 💡 선택된 상품들의 수량 * 가격을 전부 더해 총 결제금액 도출
  const totalProductPrice = cart
    .filter(item => item.checked !== false) // 체크된 항목만 계산
    .reduce((sum, item) => sum + parsePrice(item.price) * (item.quantity || 1), 0);

  // 모든 상품이 체크되어 있는지 확인
  const isAllChecked = cart.length > 0 && cart.every(item => item.checked !== false);

  return (
    <div style={{ maxWidth: "1600px", margin: "80px auto", padding: "0 20px", minHeight: "60vh", display: "flex", alignItems: "flex-start" }}>
      
      {/* ==================== 왼쪽: 장바구니 아이템 리스트 ==================== */}
      <div style={{ flex: 1 }}>
        {/* 전체선택 & 선택삭제 헤더 */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", paddingBottom: "20px", borderBottom: "1px solid #eee" , marginRight: "250px"}}>
          <label style={{ display: "flex", alignItems: "center", gap: "8px", fontSize: "12px", fontWeight: "bold", cursor: "pointer" }}>
            <input
              type="checkbox"
              checked={isAllChecked}
              onChange={(e) => toggleAllCheck(e.target.checked)}
              style={{ width: "16px", height: "16px", accentColor: "#000" }}
            />
            전체선택
          </label>
          <button style={{ background: "none", border: "none", color: "#888", fontSize: "13px", cursor: "pointer" }}>선택삭제</button>
        </div>

        {/* 장바구니가 비어있을 때 */}
        {cart.length === 0 ? (
          <div style={{marginRight: "300px", textAlign: "center", padding: "150px 0", color: "#888" }}>
            장바구니에 담긴 상품이 없습니다.
          </div>
        ) : (
          /* 장바구니에 아이템이 있을 때 */
          <div>
            {cart.map((item) => (
              <div key={item.id} style={{marginRight: "300px", display: "flex", alignItems: "flex-start", padding: "30px 0", borderBottom: "1px solid #eee", position: "relative" }}>
                
                {/* 1. 개별 체크박스 */}
                <input
                  type="checkbox"
                  checked={item.checked !== false}
                  onChange={() => toggleCheck(item.id)}
                  style={{ width: "16px", height: "16px", marginTop: "5px", marginRight: "20px", accentColor: "#000", cursor: "pointer" }}
                />

                {/* 2. 상품 정보 영역 */}
                <div style={{ flex: 1 }}>
                  <p style={{ margin: "0 0 5px 0", fontSize: "14px", color: "#111" }}>{item.name}</p>
                  <p style={{ margin: "0 0 20px 0", fontSize: "15px", fontWeight: 500 }}>{item.price}</p>
                  <p style={{ margin: "0 0 20px 0", fontSize: "13px", color: "#555" }}>[옵션: 1]</p>

                  {/* 💡 수량 조절 버튼 UI (+, - 누르면 실시간 업데이트) */}
                  <div style={{ display: "flex", alignItems: "center", border: "1px solid #ddd", width: "100px", borderRadius: "5px" }}>
                    <button onClick={() => updateQuantity(item.id, -1)} style={{ flex: 1, padding: "2px 0", background: "none", border: "none", cursor: "pointer", fontSize: "18px", color: "#555" }}>-</button>
                    <span style={{ flex: 1, textAlign: "center", fontSize: "12px" }}>{item.quantity || 1}</span>
                    <button onClick={() => updateQuantity(item.id, 1)} style={{ flex: 1, padding: "2px 0", background: "none", border: "none", cursor: "pointer", fontSize: "18px", color: "#555" }}>+</button>
                  </div>
                </div>

                {/* 3. 우측 상품 이미지 & 삭제(X) 버튼 */}
                <div style={{ position: "relative", marginLeft: "20px" }}>
                  {/* topImages가 있으면 0번째 이미지를, 없으면 imgUrl을 표시합니다 */}
                  <img src={process.env.PUBLIC_URL +item.topImages?.[0] || item.imgUrl} alt={item.name} style={{ width: "130px", height: "170px", objectFit: "cover", backgroundColor: "#f4f4f4" }} />
                  
                  {/* X 버튼 */}
                  <button
                    onClick={() => removeFromCart(item.id)}
                    style={{ position: "absolute", top: "-5px", right: "-35px", background: "none", border: "none", fontSize: "18px", color: "#999", cursor: "pointer" }}
                  >
                    ✕
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>


      {/* ==================== 오른쪽: 결제 금액 박스 (스크롤 따라다님) ==================== */}
      <div style={{ width: "400px", position: "sticky", top: "100px" }}>
        <div style={{ border: "1px solid #eee", padding: "30px", marginBottom: "20px", borderRadius: "2px" }}>
          <h3 style={{ fontSize: "17px", fontWeight: "bold", margin: "0 0 30px 0" }}>결제금액</h3>

          <div style={{ display: "flex", borderTop: "1px solid #eeee", justifyContent: "space-between", marginBottom: "15px", fontSize: "15px", color: "#555" }}>
            <span>총 상품금액</span>
            {/* 💡 toLocaleString()으로 숫자에 예쁘게 콤마(,)를 찍어줍니다 */}
            <span>{totalProductPrice.toLocaleString()} 원</span>
          </div>
          
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "25px", fontSize: "15px", color: "#555" }}>
            <span>총 배송비</span>
            <span>0 원</span>
          </div>

          <hr style={{ border: "none", borderTop: "1px solid #999", marginBottom: "25px" }} />

          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontSize: "16px", fontWeight: "bold" }}>총 결제금액</span>
            <span style={{ fontSize: "16px", fontWeight: "bold" }}>{totalProductPrice.toLocaleString()} 원</span>
          </div>
        </div>

        {/* 결제 버튼 3형제 */}
        <div style={{ display: "flex", gap: "10px", marginBottom: "10px" }}>
          <button style={{ flex: 1, padding: "16px 0", backgroundColor: "#fff", color: "#000", border: "1px solid #ddd", fontWeight: "bold", fontSize: "17px", cursor: "pointer", borderRadius: "5px" }}>선택상품주문</button>
          <button style={{ flex: 1, padding: "16px 0", backgroundColor: "#000", color: "#fff", border: "none", fontWeight: "bold", fontSize: "17px", cursor: "pointer", borderRadius: "5px" }}>전체상품주문</button>
        </div>
        
      </div>

    </div>
  );
};

export default Cart;