import React from "react";
import { Link } from "react-router-dom";

// 💡 items 를 받아옵니다.
const Magazine = ({ items }) => {
  return (
    <section style={{ width: "100%", marginTop: "60px", marginBottom: "80px" }}>
      <div style={{ maxWidth: "97%", margin: "0 auto" }}>
        {/* 상단 타이틀 영역 */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "33px",
          }}
        >
          <h2
            style={{
              fontSize: "26.5px",
              fontWeight: "870",
              margin: 0,
              color: "#000",
            }}
          >
            매거진
          </h2>
          <Link
            to="#"
            style={{
              fontSize: "11px",
              color: "#666",
              border: "1px solid #e0e0e0",
              padding: "6px 14px",
              borderRadius: "4px",
              textDecoration: "none",
            }}
          >
            모두 보기
          </Link>
        </div>

        {/* 매거진 5열 리스트 */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(5, 1fr)",
            gap: "16px",
          }}
        >
          {/* 💡 items 로 맵핑 */}
          {items &&
            items.map((item) => (
              <Link
                to="#"
                key={item.id}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  textDecoration: "none",
                }}
              >
                {/* 썸네일 이미지 */}
                <div
                  style={{
                    width: "100%",
                    aspectRatio: "3/2",
                    borderRadius: "6px",
                    overflow: "hidden",
                    backgroundColor: "#f4f4f4",
                    marginBottom: "16px",
                  }}
                >
                  <img
                    src={process.env.PUBLIC_URL +item.imgUrl}
                    alt={item.title}
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                    }}
                  />
                </div>

                {/* 텍스트 정보 */}
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "6px",
                  }}
                >
                  <div
                    style={{
                      fontSize: "15.5px",
                      fontWeight: "520",
                      color: "#000",
                      lineHeight: "1.4",
                      wordBreak: "keep-all",
                    }}
                  >
                    {item.title}
                  </div>
                  <div style={{ fontSize: "15px", color: "#888" }}>
                    {item.date}
                  </div>
                  <div style={{ marginTop: "15px" }}>
                    <span
                      style={{
                        fontSize: "13.3px",
                        color: "#444",
                        backgroundColor: "#f5f5f5",
                        padding: "4px 8px",
                        borderRadius: "4px",
                        fontWeight: "550",
                      }}
                    >
                      {item.tag}
                    </span>
                  </div>
                </div>
              </Link>
            ))}
        </div>
      </div>
    </section>
  );
};

export default Magazine;
