import React from "react";

const CurationInfo = ({ info }) => {
  return (
    <section style={{ width: "100%", textAlign: "center", padding: "60px 0 20px" }}>
      <h1 style={{ fontSize: "50px", fontWeight: "650", marginBottom: "100px", paddingTop: "100px", color: "#000" }}>
        {info.title}
      </h1>
      <p style={{ fontSize: "15px", marginBottom: "200px", color: "#111", lineHeight: "1.5", whiteSpace: "pre-line", fontWeight: "800" }}>
        {info.desc}
      </p>
    </section>
  );
};

export default CurationInfo;