import React from "react";
import Hero from "../components/home/Hero";
import Curation from "../components/home/Curation";
import Spotlight from "../components/home/Spotlight";
import TrendingBrands from "../components/home/TrendingBrands";
import NewArrivals from "../components/home/NewArrivals";
import Ranking from "../components/home/Ranking";
import MDPick from "../components/home/MDPick";
import Magazine from "../components/home/Magazine";
import ReleaseSchedule from "../components/home/ReleaseSchedule";

// 💡 통합된 JSON 데이터 불러오기
import mockData from "../data/mockData.json";

const Home = () => {
  return (
    <main className="page-transition" key="home">
      {/* 💡 모든 컴포넌트에 알맞은 이름으로 데이터를 넘겨줍니다 */}
      <Hero
        topBanners={mockData.heroTop || []}
        bottomBanners={mockData.heroBottom || []}
      />
      <Curation items={mockData.curation || []} />
      <Spotlight items={mockData.spotlight || []} />
      <TrendingBrands brands={mockData.trendingBrands || []} />
      <NewArrivals items={mockData.newArrivals || []} />
      <Ranking
        rankingItems={mockData.ranking || []}
        slideItems={mockData.slides || []}
      />
      <MDPick
        items1={mockData.mdPick?.section1 || []}
        items2={mockData.mdPick?.section2 || []}
      />
      <Magazine items={mockData.magazine || []} />
      <ReleaseSchedule schedules={mockData.releaseSchedule || []} />
    </main>
  );
};

export default Home;
