import React, { createContext, useState } from 'react';

export const BoardContext = createContext();

export const BoardProvider = ({ children }) => {
  const [reviews, setReviews] = useState([]);
  
  // 💡 올려주신 사진 속 Q&A 기본 데이터를 미리 넣어두었습니다!
  const [qas, setQas] = useState([
    { id: 1, type: "회원", title: "취소환불", date: "2026-04-16", author: "박가현", isSecret: true },
    { id: 2, type: "회원", title: "취소환불", date: "2026-04-16", author: "하이츠", isSecret: true },
    { id: 3, type: "교환/반품/환불", title: "문의", date: "2026-04-15", author: "나무", isSecret: true },
    { id: 4, type: "교환/반품/환불", title: "문의", date: "2026-04-15", author: "하이츠", isSecret: true },
    { id: 5, type: "교환/반품/환불", title: "반품 환불 문의", date: "2026-04-14", author: "김연지", isSecret: true },
  ]);

  const addReview = (review) => setReviews([review, ...reviews]);
  const addQa = (qa) => setQas([qa, ...qas]);

  return (
    <BoardContext.Provider value={{ reviews, addReview, qas, addQa }}>
      {children}
    </BoardContext.Provider>
  );
};