import React from "react";
import FooterMen from "./FooterMen";
import FooterWomen from "./FooterWomen";
import FooterLifestyle from "./FooterLifestyle";
import FooterInfo from "./FooterInfo";

const Footer = () => {
  return (
    // 💡 푸터 전체 영역 배경을 옅은 회색으로 설정
    <footer
      style={{
        width: "100%",
        backgroundColor: "#f1f1f1",
        borderTop: "1px solid #eaeaea",
      }}
    >
      <FooterMen />
      <FooterWomen />
      <FooterLifestyle />
      <FooterInfo />
    </footer>
  );
};

export default Footer;
