import React from "react";
import { Link } from "react-router-dom";

const ReleaseSchedule = () => {
  // 올려주신 캡처 이미지의 발매일정 데이터
  const scheduleData = [
    { id: 1, date: "04 / 03 / 12PM", brand: "MASCOMPANY" },
    { id: 2, date: "04 / 03 / 12PM", brand: "PERFUMECOLLECT" },
    { id: 3, date: "04 / 03 / 12PM", brand: "sunvase service" },
    { id: 4, date: "04 / 03 / 12PM", brand: "SHAKIRI" },
    { id: 5, date: "04 / 03 / 11AM", brand: "ASICS" },
    { id: 6, date: "04 / 01 / 12PM", brand: "Khakis" },
    { id: 7, date: "04 / 01 / 12PM", brand: "BOCBOK" },
    { id: 8, date: "03 / 31 / 3PM", brand: "The Innrs" },
    { id: 9, date: "03 / 31 / 12PM", brand: "preferPREFER" },
    { id: 10, date: "03 / 31 / 12PM", brand: "MADDEN" },
    { id: 11, date: "03 / 30 / 11AM", brand: "WELLBEING EXPRESS" },
    { id: 12, date: "03 / 30 / 11AM", brand: "Manhattan Records" },
    { id: 13, date: "03 / 30 / 11AM", brand: "LMC" },
  ];

  return (
    // 💡 위아래로 얇은 회색 선을 그어주고 안쪽 여백(padding)을 주어 원본과 똑같이 분리했습니다.
    <section
      style={{
        width: "100%",
        marginTop: "60px",
        marginBottom: "0px",
        borderTop: "1px solid #eaeaea",
        padding: "25px 0",
      }}
    >
      <div style={{ maxWidth: "97%", margin: "0 auto" }}>
        {/* 상단 타이틀 & 모두 보기 버튼 */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "30px",
          }}
        >
          <h2
            style={{
              fontSize: "14px",
              fontWeight: "900",
              margin: 0,
              color: "#000",
            }}
          >
            발매일정
          </h2>
          <Link
            to="#"
            style={{
              fontSize: "11px",
              color: "#666",
              border: "1px solid #e0e0e0",
              padding: "6px 14px",
              borderRadius: "4px",
              textDecoration: "none",
            }}
          >
            모두 보기
          </Link>
        </div>

        {/* 발매일정 리스트: flexWrap을 사용하여 공간이 좁아지면 자동으로 다음 줄로 넘어가게 설정 */}
        <div style={{ display: "flex", flexWrap: "wrap", gap: "17px 29px" }}>
          {scheduleData.map((item) => (
            <Link
              to="#"
              key={item.id}
              style={{
                display: "flex",
                alignItems: "center",
                gap: "7px",
                textDecoration: "none",
              }}
            >
              {/* 날짜 박스 (옅은 회색 배경) */}
              <span
                style={{
                  backgroundColor: "#f6f6f6",
                  padding: "1.5px 5px",
                  fontSize: "13.5px",
                  fontWeight: "400",
                  color: "#000",
                  borderRadius: "4px",
                }}
              >
                {item.date}
              </span>
              {/* 브랜드 이름 */}
              <span
                style={{ fontSize: "14px", color: "#333", fontWeight: "400" }}
              >
                {item.brand}
              </span>
            </Link>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ReleaseSchedule;
