import React from "react";
import { Link } from "react-router-dom";

const Curation = ({ items }) => {
  // 💡 세로 조절: marginTop(위 여백)과 marginBottom(아래 여백) 수치를 조절하세요
  return (
    <section style={{ width: "100%", marginTop: "30px", marginBottom: "30px" }}>
      {/* 💡 가로 조절: maxWidth 수치를 조절하세요 (예: 100%, 96%, 92% 등) */}
      <div
        className="section-wrap"
        style={{ maxWidth: "97%", margin: "0 auto" }}
      >
        {/* 상단 타이틀 영역 (큐레이션 & 모두 보기 버튼) */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "27px",
          }}
        >
          <h2 style={{ fontSize: "24px", fontWeight: "800", margin: 0 }}>
            큐레이션
          </h2>
          <Link
            to="#"
            style={{
              fontSize: "11px",
              color: "#666",
              border: "1px solid #e0e0e0",
              padding: "6px 14px",
              borderRadius: "4px",
              textDecoration: "none",
            }}
          >
            모두 보기
          </Link>
        </div>

        {/* 5열 그리드 영역 */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(5, 1fr)",
            gap: "16px",
          }}
        >
          {/* 💡 데이터가 없을 때 에러 방지를 위해 items && 추가 */}
          {items &&
            items.map((col) => (
              <div
                key={col.id}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: "16px",
                }}
              >
                {/* 메인 컬렉션 이미지 (정사각형) - 클릭 시 상세 페이지로 이동하도록 Link 수정 */}
                <Link
                  to={`/curation/${col.id}`} // 💡 여기를 수정했습니다!
                  style={{
                    display: "block",
                    backgroundColor: "#f4f4f4",
                    borderRadius: "6px",
                    overflow: "hidden",
                    aspectRatio: "1/1",
                    width: "100%",
                    height: "239px", // 고정된 세로 길이 (예: 300px) - 필요에 따라 조절하세요
                  }}
                >
                  <img
                    src={process.env.PUBLIC_URL +col.mainImg}
                    alt={col.title}
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                    }}
                  />
                </Link>

                {/* 타이틀 & 설명 */}
                <div style={{ textAlign: "center" }}>
                  <div
                    style={{
                      fontSize: "15px",
                      fontWeight: "420",
                      color: "#000",
                      marginBottom: "7px",
                    }}
                  >
                    {col.title}
                  </div>
                  <div
                    style={{
                      fontSize: "14px",
                      color: "#555",
                      wordBreak: "keep-all",
                      lineHeight: "1.4",
                      fontWeight: "500",
                    }}
                  >
                    {col.desc}
                  </div>
                </div>

                {/* 하위 상품 리스트 (작은 썸네일 + 정보) */}
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "14px",
                    marginTop: "0px",
                  }}
                >
                  {/* 💡 subItems 가 있을 때만 맵핑하도록 안전장치 추가 */}
                  {col.subItems &&
                    col.subItems.map((sub) => (
                      <Link
                        to={`/product/${sub.id}`} // 💡 상품을 클릭하면 개별 구매 페이지로 이동하도록 수정했습니다!
                        key={sub.id}
                        style={{
                          display: "flex",
                          gap: "11px",
                          textDecoration: "none",
                          alignItems: "center",
                        }}
                      >
                        <div
                          style={{
                            width: "55px",
                            height: "55px",
                            backgroundColor: "#f9f9f9",
                            borderRadius: "4px",
                            overflow: "hidden",
                            flexShrink: 0,
                          }}
                        >
                          <img
                            src={process.env.PUBLIC_URL +sub.thumb}
                            alt={sub.brand}
                            style={{
                              width: "100%",
                              height: "100%",
                              objectFit: "cover",
                            }}
                          />
                        </div>
                        <div
                          style={{
                            display: "flex",
                            flexDirection: "column",
                            justifyContent: "center",
                          }}
                        >
                          <span
                            style={{
                              fontSize: "14px",
                              fontWeight: "400",
                              color: "#666",
                              marginBottom: "2px",
                            }}
                          >
                            {sub.brand}
                          </span>
                          <span
                            style={{
                              fontSize: "13px",
                              color: "#000",
                              lineHeight: "1.5",
                              display: "-webkit-box",
                              WebkitLineClamp: 2,
                              WebkitBoxOrient: "vertical",
                              overflow: "hidden",
                              fontWeight: "400",
                            }}
                          >
                            {sub.name}
                          </span>
                        </div>
                      </Link>
                    ))}
                </div>
              </div>
            ))}
        </div>
      </div>
    </section>
  );
};

export default Curation;